public List<Driver> findMatching(List<Driver> drivers, List<String> ids) {
    List<Driver> result = new ArrayList<>();
    for (Driver d : drivers) {           // n iteraciones
        if (ids.contains(d.getId())) {    // m comparaciones cada una
            result.add(d);
        }
    }
    return result;
}

