public int countWays(int n, int[] memo) {
    if (n < 0) return 0;
    if (n == 0) return 1;
    if (memo[n] > 0) return memo[n];
    memo[n] = countWays(n-1, memo) + countWays(n-2, memo) + countWays(n-3, memo);
    return memo[n];
}
